type Base struct {
    // ... existing fields
    NewField string `json:"newField"`
}

// 2. mixin.go: add DB field
field.String("new_field").NotEmpty()

// 3. create.go: add to Creator[T] and Create[T]
type Creator[T any] interface {
    // ... existing
    SetNewField(string) T
}
func Create[T Creator[T]](creator Creator[T], line Base) T {
    return creator. /* chain */ .SetNewField(line.NewField)
}

// 4. mapping.go: add to DBGetter and FromDB
type DBGetter interface {
    // ... existing
    GetNewField() string
}
func FromDB[T DBGetter](dbEntity T, taxConfig *productcatalog.TaxConfig) Base {
    return Base{/* ... */ NewField: dbEntity.GetNewField()}
}

